 1	import type { FC, ReactNode } from 'react';
 2	import Linkify from 'react-linkify';
 3	import { Link } from 'react-router-dom-v5-compat';
 4	import { getResourceUrl } from 'src/modules/Providers/utils/helpers/getResourceUrl';
 5	import { useForkliftTranslation } from 'src/utils/i18n';
 6	
 7	import { NetworkMapModelRef } from '@kubev2v/types';
 8	import {
 9	  Button,
10	  ButtonVariant,
11	  Popover,
12	  Text,
13	  TextContent,
14	  TextVariants,
15	} from '@patternfly/react-core';
16	
17	import type { CellProps } from './CellProps';
18	
19	export const ErrorStatusCell: FC<CellProps & { children: ReactNode; phaseLabel: string }> = ({
20	  children,
21	  data,
22	  phaseLabel,
23	}) => {
24	  const { t } = useForkliftTranslation();
25	
26	  const { obj: networkMap } = data;
27	  const networkMapURL = getResourceUrl({
28	    name: networkMap?.metadata?.name,
29	    namespace: networkMap?.metadata?.namespace,
30	    reference: NetworkMapModelRef,
31	  });
32	
33	  // Find the error message from the status conditions
34	  const bodyContent = networkMap?.status?.conditions?.find(
35	    (condition) => condition?.category === 'Critical',
36	  )?.message;
37	
38	  // Set the footer content
39	  const footerContent = (
40	    <TextContent>
41	      <Text component={TextVariants.p}>
42	        {t(
43	          `To troubleshoot, view the network map details page
44	          and check the Forklift controller pod logs.`,
45	        )}
46	      </Text>
47	      <Text component={TextVariants.p}>
48	        <Link to={networkMapURL}>{t('View network map details')}</Link>
49	      </Text>
50	    </TextContent>
51	  );
52	
53	  return (
54	    <Popover
55	      headerContent={phaseLabel}
56	      bodyContent={bodyContent && <Linkify>{bodyContent}</Linkify>}
57	      footerContent={footerContent}
58	    >
59	      <Button
60	        variant={ButtonVariant.link}
61	        isInline
62	        data-testid="popover-status-button-network-maps-list"
63	      >
64	        {children}
65	      </Button>
66	    </Popover>
67	  );
68	};

